import{_ as t,o as n,c as s,ae as l}from"./chunks/framework.BdQd5MxT.js";const c=JSON.parse('{"title":"演讲模板 — 可复用框架","description":"","frontmatter":{},"headers":[],"relativePath":"proposals/talk-template.md","filePath":"proposals/talk-template.md"}'),e={name:"proposals/talk-template.md"};function o(i,a,r,p,d,h){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="演讲模板-—-可复用框架" tabindex="-1">演讲模板 — 可复用框架 <a class="header-anchor" href="#演讲模板-—-可复用框架" aria-label="Permalink to &quot;演讲模板 — 可复用框架&quot;">​</a></h1><blockquote><p>WLB 🦞 | 教练建议 P0 | 2026-03-22 基于 2026-03-15 清华科技园 Meetup 实战经验提炼</p></blockquote><hr><h2 id="选题标准" tabindex="-1">选题标准 <a class="header-anchor" href="#选题标准" aria-label="Permalink to &quot;选题标准&quot;">​</a></h2><p>好的演讲选题应该同时满足：</p><ol><li><strong>有真实经历</strong> — 不是纸上谈兵，有实际踩坑数据</li><li><strong>有可复用性</strong> — 听完能自己动手做</li><li><strong>有反直觉的点</strong> — &quot;我以为 X，结果是 Y&quot; 比 &quot;X 很好&quot; 更有吸引力</li><li><strong>和 OPC 目标对齐</strong> — 讲完能引流到公众号/网站</li></ol><p><strong>选题矩阵</strong>：</p><table tabindex="0"><thead><tr><th>好选题</th><th>差选题</th></tr></thead><tbody><tr><td>&quot;AI Agent 宕机 6 小时后我做了什么&quot;</td><td>&quot;AI Agent 技术介绍&quot;</td></tr><tr><td>&quot;两个 AI Agent 怎么协作不打架&quot;</td><td>&quot;多 Agent 系统概述&quot;</td></tr><tr><td>&quot;用 Tailscale 稳定使用 Claude Code&quot;</td><td>&quot;VPN 技术详解&quot;</td></tr></tbody></table><hr><h2 id="大纲模板-45-分钟演讲" tabindex="-1">大纲模板（45 分钟演讲） <a class="header-anchor" href="#大纲模板-45-分钟演讲" aria-label="Permalink to &quot;大纲模板（45 分钟演讲）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 开场钩子 (3 min)</span></span>
<span class="line"><span>   - 一个问题 / 一个意外 / 一个数据</span></span>
<span class="line"><span>   - 例：&quot;我们的 AI Agent 在群里公开泄露了 API key...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 背景交代 (5 min)</span></span>
<span class="line"><span>   - 我是谁、在做什么、为什么做这个</span></span>
<span class="line"><span>   - 简短，不要超过 5 分钟</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 核心故事 (20 min)</span></span>
<span class="line"><span>   - 分 3-4 个阶段讲</span></span>
<span class="line"><span>   - 每个阶段：遇到了什么 → 怎么想的 → 怎么做的 → 结果如何</span></span>
<span class="line"><span>   - 用具体数据：延迟 80ms、花费 $7/月、宕机 6 小时</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 可复用的经验 (10 min)</span></span>
<span class="line"><span>   - 提炼 3-5 条，每条配一个真实案例</span></span>
<span class="line"><span>   - 不要讲理论，讲&quot;我试过 X，结果 Y，所以现在用 Z&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 下一步 + 互动 (7 min)</span></span>
<span class="line"><span>   - 接下来要做什么</span></span>
<span class="line"><span>   - Q&amp;A</span></span></code></pre></div><hr><h2 id="素材清单" tabindex="-1">素材清单 <a class="header-anchor" href="#素材清单" aria-label="Permalink to &quot;素材清单&quot;">​</a></h2><p>每次演讲前准备：</p><ul><li>[ ] <strong>架构图</strong>（1-2 张）— ASCII 或 SVG，展示系统全貌</li><li>[ ] <strong>数据表格</strong>（2-3 个）— 对比表、费用表、时间线</li><li>[ ] <strong>截图</strong>（3-5 张）— Slack 对话、终端输出、部署界面</li><li>[ ] <strong>代码片段</strong>（可选）— 关键配置，不超过 20 行</li><li>[ ] <strong>失败案例</strong>（至少 1 个）— 比成功案例更有说服力</li></ul><hr><h2 id="时间线-提前-2-周启动" tabindex="-1">时间线（提前 2 周启动） <a class="header-anchor" href="#时间线-提前-2-周启动" aria-label="Permalink to &quot;时间线（提前 2 周启动）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>动作</th><th>负责</th></tr></thead><tbody><tr><td>T-14 天</td><td>确定选题 + 大纲</td><td>MiaoDX + WLB</td></tr><tr><td>T-10 天</td><td>素材收集 + 草稿</td><td>GSD + WLB</td></tr><tr><td>T-7 天</td><td>初版 PPT/HTML</td><td>GSD</td></tr><tr><td>T-3 天</td><td>内部预演 + 修改</td><td>全员</td></tr><tr><td>T-1 天</td><td>最终版本锁定</td><td>MiaoDX</td></tr><tr><td>T+1 天</td><td>复盘 + 整理成社区帖子</td><td>GSD + WLB</td></tr></tbody></table><hr><h2 id="_03-15-meetup-实战复盘" tabindex="-1">03-15 Meetup 实战复盘 <a class="header-anchor" href="#_03-15-meetup-实战复盘" aria-label="Permalink to &quot;03-15 Meetup 实战复盘&quot;">​</a></h2><h3 id="做得好的" tabindex="-1">做得好的 <a class="header-anchor" href="#做得好的" aria-label="Permalink to &quot;做得好的&quot;">​</a></h3><ul><li>有真实数据和截图，说服力强</li><li>三层防护架构的讲解效果好</li><li>双平台对比（ClawCloud vs Railway）实用</li></ul><h3 id="可以改进的" tabindex="-1">可以改进的 <a class="header-anchor" href="#可以改进的" aria-label="Permalink to &quot;可以改进的&quot;">​</a></h3><ul><li>开场钩子不够强 — 下次用更戏剧化的开头</li><li>时间控制 — 中间部分拖沓，Q&amp;A 时间被压缩</li><li>互动环节少 — 可以提前准备 2-3 个引导问题</li></ul><h3 id="下次尝试" tabindex="-1">下次尝试 <a class="header-anchor" href="#下次尝试" aria-label="Permalink to &quot;下次尝试&quot;">​</a></h3><ul><li>开场直接放&quot;宕机 6 小时&quot;的故事，不要从背景开始</li><li>中间穿插 1-2 个小互动（举手投票、现场 demo）</li><li>结尾放二维码，引流到公众号</li></ul><hr><h2 id="ppt-制作规范" tabindex="-1">PPT 制作规范 <a class="header-anchor" href="#ppt-制作规范" aria-label="Permalink to &quot;PPT 制作规范&quot;">​</a></h2><ul><li><strong>风格</strong>：深色背景 + 亮色文字（终端风格）</li><li><strong>字体</strong>：中文用思源黑体，英文用 JetBrains Mono</li><li><strong>每页字数</strong>：≤ 30 字，图表优先</li><li><strong>工具</strong>：HTML 自包含（放在 <code>share/presentations/</code>）</li><li><strong>配套素材</strong>：图片放同目录，用相对路径引用</li></ul><hr><p><em>Coach 要求的 P0 文档 | 2026-03-22 完成</em><em>基于 03-15 Meetup 实战经验提炼</em></p>`,31)])])}const q=t(e,[["render",o]]);export{c as __pageData,q as default};
